  auto ALTERNATE_NAMES__ = ALTERNATE_NAMES ? _fbb.CreateVector<::flatbuffers::Offset<::flatbuffers::String>>(*ALTERNATE_NAMES) : 0;
  auto EMAIL__ = EMAIL ? _fbb.CreateString(EMAIL) : 0;
